def llm_verifier(candidate: str, original_prompt: str) -> float:
    """
    Ask the LLM to score a candidate response on a 1–10 scale.
    Returns a normalized score between 0.0 and 1.0.
    """
    response = client.messages.create(
        model=MODEL,
        max_tokens=64,
        messages=[{
            "role": "user",
            "content": (
                f"Rate the quality of this response to the question below on a scale of 1–10.\n"
                f"Consider: correctness, completeness, clarity.\n\n"
                f"Question: {original_prompt}\n\n"
                f"Response: {candidate}\n\n"
                "Output only a single integer from 1 to 10."
            ),
        }],
    )
    try:
        return int(response.content[0].text.strip()) / 10.0
    except ValueError:
        return 0.5

import re, ast

def math_heuristic_verifier(response: str) -> float:
    """Returns 1.0 if response has a clear final answer, 0.0 if empty."""
    clean = response.strip()
    if not clean:
        return 0.0
    # Confident answer patterns
    if re.search(r"therefore.*=|the answer is|\\boxed\{", clean, re.IGNORECASE):
        return 1.0
    # Has a number somewhere
    if re.search(r"\d+", clean):
        return 0.5
    return 0.0


def code_parse_verifier(response: str) -> float:
    """Returns 1.0 if the response contains syntactically valid Python."""
    # Extract code block if present
    match = re.search(r"```python\n(.*?)```", response, re.DOTALL)
    code = match.group(1) if match else response
    try:
        ast.parse(code)
        return 1.0
    except SyntaxError:
        return 0.0

def llm_critic_verifier(response: str, question: str) -> float:
    """
    Use a focused LLM call to score the response on correctness + completeness.
    Returns 0.0–1.0.
    """
    critic_response = client.messages.create(
        model=MODEL, max_tokens=64,
        messages=[{
            "role": "user",
            "content": (
                f"Question: {question}\n\n"
                f"Answer: {response}\n\n"
                "Score this answer on correctness and completeness from 1 to 10. "
                "Be strict: a wrong step should score ≤ 4. "
                "Output only the integer."
            ),
        }],
    )
    try:
        return int(critic_response.content[0].text.strip()) / 10.0
    except ValueError:
        return 0.5
